Extend the pipe-to-shell pattern to check for any token after '|' that names a known shell binary:

```rust
const SHELL_BINARIES: &[&str] = &["sh", "bash", "zsh", "fish", "dash", "ksh", "csh", "tcsh"];
if has_pipe_to_shell(lower, SHELL_BINARIES) { ... }

fn has_pipe_to_shell(cmd: &str, shells: &[&str]) -> bool {
    if let Some(after_pipe) = cmd.split_once('|').map(|(_, r)| r.trim()) {
        let first_word = after_pipe.split_ascii_whitespace().next().unwrap_or("");
        let binary = first_word.rsplit('/').next().unwrap_or(first_word);
        shells.contains(&binary)
    } else { false }
}
```

